html:
{% raw %}<!DOCTYPE html>
<html>
<head>
<style>
  body { font-family: monospace; font-size: 12px; width: 80mm; }
  h2 { text-align: center; font-size: 16px; margin: 0; }
  .divider { border-top: 1px dashed #000; margin: 6px 0; }
  table { width: 100%; }
  td { padding: 2px 4px; vertical-align: top; }
  .qty { width: 30px; text-align: right; }
  .station { font-size: 14px; font-weight: bold; text-align: center; }
  .time { font-size: 10px; text-align: center; color: #555; }
</style>
</head>
<body>
  <h2>{{ doc.kitchen_station }}</h2>
  <div class="time">{{ doc.creation }}</div>
  <div class="divider"></div>
  <div><strong>Order:</strong> {{ doc.order }}</div>
  <div><strong>Table:</strong> {{ doc.table_no }}</div>
  <div class="divider"></div>
  <table>
    {% for item in doc.items %}
    <tr>
      <td class="qty">{{ item.qty }}</td>
      <td>{{ item.item_name or item.menu_item }}
        {% if item.special_instructions %}<br><em>* {{ item.special_instructions }}</em>{% endif %}
      </td>
    </tr>
    {% endfor %}
  </table>
  <div class="divider"></div>
  <div style="text-align:center; font-size:10px;">KOT# {{ doc.name }}</div>
</body>
</html>{% endraw %}
